import{_ as a,o as i,c as e,a2 as t}from"./chunks/framework.D5wUhsuj.js";const c=JSON.parse('{"title":"GPU Administration","description":"","frontmatter":{},"headers":[],"relativePath":"admin/gpu.md","filePath":"admin/gpu.md","lastUpdated":1783546178000}'),n={name:"admin/gpu.md"};function l(r,s,o,p,h,d){return i(),e("div",null,[...s[0]||(s[0]=[t(`<h1 id="gpu-administration" tabindex="-1">GPU Administration <a class="header-anchor" href="#gpu-administration" aria-label="Permalink to &quot;GPU Administration&quot;">​</a></h1><p>prokube deployments that include GPUs commonly use the <a href="https://docs.nvidia.com/datacenter/cloud-native/gpu-operator/latest/index.html" target="_blank" rel="noreferrer">NVIDIA GPU Operator</a> to install and manage drivers, device plugins, monitoring, and related components.</p><p>GPU availability is deployment-specific. Users request GPUs from Labs, Pipelines, model-serving workloads, and custom Kubernetes resources, but administrators are responsible for node preparation, operator configuration, quota, monitoring, and capacity planning.</p><h2 id="user-workload-requests" tabindex="-1">User Workload Requests <a class="header-anchor" href="#user-workload-requests" aria-label="Permalink to &quot;User Workload Requests&quot;">​</a></h2><p>Kubernetes workloads request GPUs with the <code>nvidia.com/gpu</code> resource:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">apiVersion</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">v1</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">kind</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">Pod</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">metadata</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">gpu-test</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">spec</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  containers</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    - </span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">cuda</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">      image</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">nvidia/cuda:12.4.1-base-ubuntu22.04</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">      command</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;nvidia-smi&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">      resources</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">        limits</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">          nvidia.com/gpu</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span></span></code></pre></div><p>The selected image still needs compatible user-space libraries for the workload. The GPU Operator mounts host driver components into the container; it does not make every framework version compatible automatically.</p><h2 id="timeslicing-and-mig" tabindex="-1">Timeslicing and MIG <a class="header-anchor" href="#timeslicing-and-mig" aria-label="Permalink to &quot;Timeslicing and MIG&quot;">​</a></h2><p>GPU sharing strategy is a platform capacity decision.</p><p><strong>Timeslicing</strong> exposes multiple logical GPUs on one physical GPU. Multiple pods can request <code>nvidia.com/gpu: 1</code> and share the same card. Compute is shared opportunistically, and memory is not strongly isolated: one workload can still consume enough memory to disrupt others.</p><p><strong>MIG</strong> partitions supported GPUs at the hardware level. Each MIG instance has dedicated memory and compute slices, which gives stronger isolation and more predictable behavior. MIG is supported only on specific NVIDIA GPUs and requires planned node configuration.</p><p>Use NVIDIA&#39;s upstream documentation for supported devices and exact operator settings:</p><ul><li><a href="https://docs.nvidia.com/datacenter/cloud-native/gpu-operator/latest/gpu-operator-mig.html" target="_blank" rel="noreferrer">GPU Operator with MIG</a></li><li><a href="https://docs.nvidia.com/datacenter/cloud-native/gpu-operator/latest/gpu-sharing.html" target="_blank" rel="noreferrer">GPU Operator time-slicing</a></li></ul><h2 id="admin-configuration" tabindex="-1">Admin Configuration <a class="header-anchor" href="#admin-configuration" aria-label="Permalink to &quot;Admin Configuration&quot;">​</a></h2><p>GPU sharing is normally configured through the NVIDIA <code>ClusterPolicy</code> and, for MIG, node labels such as <code>nvidia.com/mig.config</code>. In GitOps-managed deployments, update the authoritative deployment configuration rather than editing generated live resources.</p><p>Useful inspection commands:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nodes</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> custom-columns=NAME:.metadata.name,GPUS:.status.allocatable.nvidia</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\.</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">com/gpu</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> describe</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> node</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">gpu-node-nam</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pods</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -A</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> custom-columns=NAMESPACE:.metadata.namespace,NAME:.metadata.name,GPUS:.spec.containers[</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">*</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">].resources.limits.nvidia</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\.</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">com/gpu</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clusterpolicy</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -A</span></span></code></pre></div><p>Changing sharing strategy can evict workloads, reconfigure devices, and temporarily remove GPU capacity from the scheduler. Drain or stop affected workloads first and plan a maintenance window.</p><h2 id="monitoring" tabindex="-1">Monitoring <a class="header-anchor" href="#monitoring" aria-label="Permalink to &quot;Monitoring&quot;">​</a></h2><p>GPU-enabled deployments usually expose GPU metrics through the NVIDIA DCGM exporter and Grafana dashboards. Monitor at least:</p><ul><li>allocated versus allocatable GPUs by node;</li><li>GPU memory usage;</li><li>utilization and throttling;</li><li>unhealthy devices;</li><li>model-serving or notebook pods that reserve GPUs but remain idle.</li></ul><p>GPU metrics can expose workload names and resource usage across namespaces. Scope dashboards and Grafana permissions accordingly.</p><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Symptom</th><th>Check</th></tr></thead><tbody><tr><td>Pod remains pending</td><td>Confirm allocatable GPUs, workspace quota, node selectors, tolerations, and whether all GPU nodes are already full.</td></tr><tr><td>Pod starts but framework cannot see a GPU</td><td>Check <code>nvidia-smi</code> in the container, image CUDA/framework compatibility, and GPU Operator pod health.</td></tr><tr><td>Timesliced workloads interfere with each other</td><td>Reduce concurrency, use larger nodes, or move isolation-sensitive workloads to MIG-capable nodes.</td></tr><tr><td>MIG configuration does not apply</td><td>Check GPU support, node labels, GPU Operator logs, and whether existing workloads must be stopped before repartitioning.</td></tr></tbody></table><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./../labs/">Labs</a></li><li><a href="./../mlops/pipelines.html">Pipelines</a></li><li><a href="./../mlops/model_serving.html">Model Serving</a></li><li><a href="./operations_runbooks.html">Operations Runbooks</a></li></ul>`,26)])])}const g=a(n,[["render",l]]);export{c as __pageData,g as default};
